# {count} Rails POST calls (authenticity_token from meta tag).
for _i in range({count}):
    page.evaluate('''async () => {{
        const meta = document.querySelector('meta[name=csrf-token]');
        const token = meta ? meta.getAttribute('content') : '';
        await fetch('/api/test_endpoint', {{
            method: 'POST',
            headers: {{'Content-Type':'application/json',
                      'X-CSRF-Token': token}},
            credentials: 'same-origin',
            body: JSON.stringify({{}})
        }});
    }}''')

# Run RSpec subprocess + assert exit code 0.
import subprocess
proc = subprocess.run(['bin/rspec', '{spec_path}'],
                      capture_output=True, text=True, timeout=300)
EVIDENCE['checks']['rspec_{spec_path}'] = {{
    'returncode': proc.returncode,
    'stdout_tail': (proc.stdout or '')[-400:],
    'pass': proc.returncode == 0
}}

# Assert ActiveRecord {callback} fires on {model}.
import subprocess
rb_script = '''
    require_relative "config/environment"
    counter = 0
    {model}.send(:define_method, :_audit) {{ counter += 1 }}
    {model}.set_callback(:create, :{callback_phase}, :_audit)
    instance = {model}.create!(name: "audit-test")
    puts "AUDIT_CALLBACK_FIRES=#{{counter}}"
'''
proc = subprocess.run(['bin/rails', 'runner', rb_script],
                      capture_output=True, text=True, timeout=60)
fires = 0
for line in (proc.stdout or '').splitlines():
    if line.startswith('AUDIT_CALLBACK_FIRES='):
        fires = int(line.split('=',1)[1])
EVIDENCE['checks']['{model}_{callback}'] = {{
    'fires': fires,
    'pass': fires >= 1
}}

# Verify RSpec let block resolves + memoizes.
import subprocess
proc = subprocess.run(
    ['bin/rspec', '--example', 'uses let({name})',
     '--format', 'documentation'],
    capture_output=True, text=True, timeout=120
)
EVIDENCE['checks']['rspec_let_{name}'] = {{
    'returncode': proc.returncode,
    'stdout_tail': (proc.stdout or '')[-300:],
    'pass': proc.returncode == 0 and 'examples, 0 failures' in (proc.stdout or '')
}}

# Run Capybara system test for {feature}.
import subprocess
proc = subprocess.run(
    ['bin/rails', 'test:system', 'TEST=test/system/{feature}_test.rb'],
    capture_output=True, text=True, timeout=300
)
EVIDENCE['checks']['system_{feature}'] = {{
    'returncode': proc.returncode,
    'stdout_tail': (proc.stdout or '')[-400:],
    'pass': proc.returncode == 0 and 'failures' not in (proc.stdout or '').lower()
}}

# Execute rake task + assert exit code.
import subprocess
proc = subprocess.run(['bin/rake', '{task}'],
                      capture_output=True, text=True, timeout=120)
EVIDENCE['checks']['rake_{task}'] = {{
    'returncode': proc.returncode,
    'stdout_tail': (proc.stdout or '')[-400:],
    'pass': proc.returncode == 0
}}
